import{_ as r,o as t,c as a,a7 as p}from"./chunks/framework.BgApuQ2e.js";const s="/images/creepy-kids-in-creepy-vintage-ads/1-resized.jpg",o="/images/creepy-kids-in-creepy-vintage-ads/4.jpg",g="/images/creepy-kids-in-creepy-vintage-ads/2.jpg",i="/images/creepy-kids-in-creepy-vintage-ads/3.jpg",n="/images/creepy-kids-in-creepy-vintage-ads/5.jpg",A="/images/creepy-kids-in-creepy-vintage-ads/6.jpg",c="/images/creepy-kids-in-creepy-vintage-ads/7.jpg",l="/images/creepy-kids-in-creepy-vintage-ads/8.jpg",m="/images/creepy-kids-in-creepy-vintage-ads/9.jpg",h="/images/creepy-kids-in-creepy-vintage-ads/11.jpg",d="/images/creepy-kids-in-creepy-vintage-ads/12.jpg",b="/images/creepy-kids-in-creepy-vintage-ads/13.jpg",_="/images/creepy-kids-in-creepy-vintage-ads/14.jpg",y="/images/creepy-kids-in-creepy-vintage-ads/15.jpg",k="/images/creepy-kids-in-creepy-vintage-ads/16.jpg",f="/images/creepy-kids-in-creepy-vintage-ads/17.jpg",j="/images/creepy-kids-in-creepy-vintage-ads/18.jpg",u="/images/creepy-kids-in-creepy-vintage-ads/19.jpg",E="/images/creepy-kids-in-creepy-vintage-ads/20.jpg",v="/images/creepy-kids-in-creepy-vintage-ads/21.jpg",w="/images/creepy-kids-in-creepy-vintage-ads/23.jpg",I="/images/creepy-kids-in-creepy-vintage-ads/25.jpg",U="/images/creepy-kids-in-creepy-vintage-ads/24.jpg",P="/images/creepy-kids-in-creepy-vintage-ads/26.jpg",q="/images/creepy-kids-in-creepy-vintage-ads/27.jpeg",x="/images/creepy-kids-in-creepy-vintage-ads/28.jpg",C="/images/creepy-kids-in-creepy-vintage-ads/29.jpg",V="/images/creepy-kids-in-creepy-vintage-ads/30.jpg",T="/images/creepy-kids-in-creepy-vintage-ads/31.jpg",Q="/images/creepy-kids-in-creepy-vintage-ads/32.jpg",R="/images/creepy-kids-in-creepy-vintage-ads/33.jpg",Y="/images/creepy-kids-in-creepy-vintage-ads/34.jpg",S="/images/creepy-kids-in-creepy-vintage-ads/35.jpg",W="/images/creepy-kids-in-creepy-vintage-ads/37.jpg",B="/images/creepy-kids-in-creepy-vintage-ads/38.jpg",J="/images/creepy-kids-in-creepy-vintage-ads/39.jpg",X="/images/creepy-kids-in-creepy-vintage-ads/36.jpg",H="/images/creepy-kids-in-creepy-vintage-ads/pinit_fg_en_rect_gray_20.png",L=JSON.parse('{"title":"Creepy Kids in Creepy Vintage Ads","description":"","frontmatter":{"title":"Creepy Kids in Creepy Vintage Ads","titleZh":"诡异复古广告中的诡异小孩","date":"2013-08-16T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/08/creepy-kids-in-creepy-vintage-ads.html","slug":"creepy-kids-in-creepy-vintage-ads"},"headers":[],"relativePath":"posts/creepy-kids-in-creepy-vintage-ads.md","filePath":"posts/creepy-kids-in-creepy-vintage-ads.md","lastUpdated":1782886257000}'),K={name:"posts/creepy-kids-in-creepy-vintage-ads.md"};function O(M,e,Z,F,G,N){return t(),a("div",null,[...e[0]||(e[0]=[p('<h1 id="诡异复古广告中的诡异小孩-·-creepy-kids-in-creepy-vintage-ads" tabindex="-1">诡异复古广告中的诡异小孩 · Creepy Kids in Creepy Vintage Ads <a class="header-anchor" href="#诡异复古广告中的诡异小孩-·-creepy-kids-in-creepy-vintage-ads" aria-label="Permalink to &quot;诡异复古广告中的诡异小孩 · Creepy Kids in Creepy Vintage Ads&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/08/creepy-kids-in-creepy-vintage-ads.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/08/creepy-kids-in-creepy-vintage-ads.html</a> · 2013-08-16</p></blockquote><p>致所有目前年龄在 55 到 110 岁之间的美国人:我知道你们的秘密了。</p><p>你们有一个极其诡异的童年。</p><p>你们现在生活在 2014 年,假装自己的人生一切正常,可事实证明,你们成长的那些年一点都不正常。它们怪得离谱。你们也一样。只能这么说了。</p><p>我之所以知道,是因为我刚刚花了一整天时间翻看 1900、10、20、30、40、50 年代那些让人不安的广告,主角全是小孩,请原谅我需要过几天才能重新面对你们。</p><p>否认是没用的,因为我在下面精心整理了大量证据。让我们按类别一个个来看:</p><h2 id="饿得诡异的小女孩" tabindex="-1"><strong>饿得诡异的小女孩</strong> <a class="header-anchor" href="#饿得诡异的小女孩" aria-label="Permalink to &quot;**饿得诡异的小女孩**&quot;">​</a></h2><p><a href="https://2.bp.blogspot.com/-K_ysW1Fsdkk/Ug2pK9WvKUI/AAAAAAAAE8A/LPPTXw0-3j0/s1600/1+resized.jpg" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>这小姑娘真该冷静一下。那副癫狂的表情加上急切的小手,完全过头了。就是几片抹了果酱的白面包而已。</p><p><a href="https://4.bp.blogspot.com/-Ag4yTkUFoRY/Ug15Zm2x5iI/AAAAAAAAE60/AJKcOqjms9A/s1600/4.jpg" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>好吧,那几块低档冰淇淋看起来是挺诱人。但也不至于<em>完全被摄住魂魄</em>吧。松开栏杆,控制一下自己。</p><p><a href="https://2.bp.blogspot.com/-tElg4mQIxew/Ug15SV5a1_I/AAAAAAAAE38/-fAs5bNGx6w/s1600/2.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>我懂,一大盘肉,你饿了,但还是稍微收敛一点。你又不是狗。</p><p><a href="https://1.bp.blogspot.com/-R55OsymgLa4/Ug15Vi_4WbI/AAAAAAAAE5Q/6OFiGVt3egk/s1600/3.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>说到这个,这女孩的行为简直像未开化的野兽。你可以想吃 Cocoanut,同时保持点体面吧。</p><h2 id="长着老人脸的小孩" tabindex="-1"><strong>长着老人脸的小孩</strong> <a class="header-anchor" href="#长着老人脸的小孩" aria-label="Permalink to &quot;**长着老人脸的小孩**&quot;">​</a></h2><p><a href="https://2.bp.blogspot.com/-5o0W641ZYLA/Ug15ZmFbESI/AAAAAAAAE7E/hAMJbl0ow0E/s1600/5.jpg" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>一个 6 岁小孩,眼角皱纹也太特么多了。</p><p><a href="https://2.bp.blogspot.com/-HBQU7GwbX6g/Ug15Z_ehgeI/AAAAAAAAE68/O6EJt9dk-TM/s1600/6.jpg" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>好吧,这广告里两个人都得给我他妈的清醒清醒。我本想训斥那小孩,但我们都看得出来他这副神经病样是跟谁学的。总之,他与其花时间对着一杯 V-8 果汁垂涎欲滴,不如担心一下自己那张脸和那个发型看起来像个 75 岁的共和党老头。</p><p><a href="https://2.bp.blogspot.com/-5jO9Vf2nQSs/Ug15aV3zbkI/AAAAAAAAE7M/OIuE47YPixE/s1600/7.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>你这么点大,用得着靠一句 85 岁老头才会说的「Say」来引起别人注意吗?还有你干嘛喝这么多汽水——你才 7 个月大好吗。</p><p><a href="https://2.bp.blogspot.com/-7KIVop8Lyzo/Ug15avGKVVI/AAAAAAAAE7U/4r2MEIrfRr4/s1600/8.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>好吧,这真是一条精彩的人生轨迹。所以显然,上一则广告里的小孩决定把他那点小把戏发展成一份事业,<em>真的在 Hires&#39; Rootbeer 找了份工作</em>。汽水喝多了终究是要付出代价的,他现在看起来 50 岁。</p><p>既然都说到这儿了,不如把这个现象好好挖一挖——</p><h2 id="更多喝汽水的婴儿" tabindex="-1"><strong>更多喝汽水的婴儿</strong> <a class="header-anchor" href="#更多喝汽水的婴儿" aria-label="Permalink to &quot;**更多喝汽水的婴儿**&quot;">​</a></h2><p><a href="https://2.bp.blogspot.com/-yJgF-31th5k/Ug15ayYxV2I/AAAAAAAAE7c/yRZ2ZdIZWgQ/s1600/9.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>美国汽水委员会 (The Soda Pop Board of America) 的思路大概是这样:「我们把希望是真的事情写下来,然后就把它做成广告吧。」</p><p><a href="https://3.bp.blogspot.com/-fUwJ6H1bMkQ/Ug15PQKY6vI/AAAAAAAAE28/ppPraUInUk0/s1600/11.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>纯粹的快乐!是的,你真的做出了什么了不起的事情——你给一个才活了 50 天的人喝了一杯气泡糖水,然后得到了正面反应。</p><p><a href="https://3.bp.blogspot.com/-0L9WJkebOpE/Ug15Oo-IzqI/AAAAAAAAE2w/HzyadzaoY2o/s1600/12.jpg" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>就是这样。往新生儿的喉咙里灌就完事了。</p><p>顺理成章地过渡到:</p><h2 id="优秀育儿典范" tabindex="-1"><strong>优秀育儿典范</strong> <a class="header-anchor" href="#优秀育儿典范" aria-label="Permalink to &quot;**优秀育儿典范**&quot;">​</a></h2><p><a href="https://1.bp.blogspot.com/-XKPeNZTwJv0/Ug15PPLE-6I/AAAAAAAAE24/f-FxQxEy3xc/s1600/13.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>现代父母给 2 个月大的宝宝一个奶嘴。也许再加个小毯子。1905 年呢?他们给婴儿递上一把剃刀,叫他开始刮胡子。</p><p><a href="https://4.bp.blogspot.com/-gYCQ9B-Du3g/Ug15PhkOpYI/AAAAAAAAE3E/BR23nzaMW4Q/s1600/14.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>考虑到<em>他被锁在浴室里</em>,缺乏日照根本算不上这个宝宝最大的问题。这产品简直就是专门卖给那种把孩子养在肮脏、黑暗的浴室角落里、永远不让他们看见或知晓外面世界的父母的。</p><p><a href="https://1.bp.blogspot.com/-9bY59dccUhg/Ug15RBTnHgI/AAAAAAAAE3k/b7doU5sPx9k/s1600/15.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>在这个可怜小女孩的胸前,写着「爸爸说不会伤到我们的!」所以爸爸的逻辑是:「我搞到了一把带儿童锁的枪——这下我 2 岁的女儿终于可以抱着枪睡觉了。」</p><p><a href="https://4.bp.blogspot.com/-aIB3YXQ61VA/Ug15P9MawLI/AAAAAAAAE3M/i1uyTQ75Q18/s1600/16.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>「你能在杜邦玻璃纸 (Du Pont Cellophane) 里看到那么多好东西。」比如,显然,被闷死的婴儿。</p><p><a href="https://3.bp.blogspot.com/-n_id_fP2gwI/Ug15QQW8bfI/AAAAAAAAE3Y/QXJRPx8090k/s1600/17.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>无可奉告。</p><h2 id="婴儿针对母亲吸烟成瘾发表睿智见解" tabindex="-1"><strong>婴儿针对母亲吸烟成瘾发表睿智见解</strong> <a class="header-anchor" href="#婴儿针对母亲吸烟成瘾发表睿智见解" aria-label="Permalink to &quot;**婴儿针对母亲吸烟成瘾发表睿智见解**&quot;">​</a></h2><p><a href="https://3.bp.blogspot.com/-XH0RApNts2k/Ug15QygbfeI/AAAAAAAAE3g/SFvhXdlHR5E/s1600/18.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>真的吗,这位女士?你烟瘾大到连你那不谙世事的婴儿都忍不住要评论了,而你却像跟成年人聊天一样回应,还煞有介事地阐述这个牌子香烟的优点?</p><p><a href="https://2.bp.blogspot.com/-OVGVezyB-wU/Ug15RqL2GTI/AAAAAAAAE3w/fEjknzD93dM/s1600/19.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>好吧现在这他妈是什么情况?这孩子是万宝路 (Marlboro) 派来的?他从哪儿学来这种操纵人心的招数?</p><p><a href="https://3.bp.blogspot.com/-_6HHL7TxQ-s/Ug15SK-S6fI/AAAAAAAAE30/Z150Fa7NFPY/s1600/20.jpg" target="_blank" rel="noreferrer"><img src="'+E+'" alt=""></a></p><p>让我们列一下事实:</p><ol><li>这个母亲有烟瘾</li><li>她有时还打自己的孩子</li><li>这个婴儿两件事都知道,而且真的学会了 <em>智胜</em> 这个可怕的女人——他摸透了她的行为规律,懂得利用她的烟瘾来减轻虐待。</li></ol><p>咱们继续。</p><h2 id="长得欠揍到离谱的红发小男孩-兴奋地要把食物塞进他们那副贱兮兮的嘴里" tabindex="-1"><strong>长得欠揍到离谱的红发小男孩,兴奋地要把食物塞进他们那副贱兮兮的嘴里</strong> <a class="header-anchor" href="#长得欠揍到离谱的红发小男孩-兴奋地要把食物塞进他们那副贱兮兮的嘴里" aria-label="Permalink to &quot;**长得欠揍到离谱的红发小男孩,兴奋地要把食物塞进他们那副贱兮兮的嘴里**&quot;">​</a></h2><p><a href="https://3.bp.blogspot.com/-l4rATylocw4/Ug15Ssj1TtI/AAAAAAAAE4E/2pAQY_DRYDg/s1600/21.jpg" target="_blank" rel="noreferrer"><img src="'+v+'" alt=""></a></p><p>这张图我几乎看不下去,烦死我了。</p><p><a href="https://1.bp.blogspot.com/-r5lCXqt0Efs/Ug15TENdhRI/AAAAAAAAE4Q/bATHfwqeHh4/s1600/23.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>一个稍微有点自我意识的孩子可能不太会喜欢这么明显、这么带贬义的外号。但这位红毛 (Ginger) 小哥此刻正为了喝这罐汽水而狂喜到爆炸,大脑里根本容不下别的念头。</p><p><a href="https://4.bp.blogspot.com/-B776mbzXjMI/Ug15UHF0s6I/AAAAAAAAE4k/RTwaSx9PmJ4/s1600/25.JPG" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p>这孩子看起来野得不行。还好他从往邻居家扔鸡蛋的活动中抽出了空,来为一杯橙汁高潮一下。</p><p><a href="https://3.bp.blogspot.com/-3yAnJ-63r0w/Ug15T8O28HI/AAAAAAAAE4g/l1yTINFoKa0/s1600/24.jpg" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>嗯我打赌你确实“希望自己有一百万块奥利奥 (Oreo)”。知道为啥吗?因为你是个 50 年代广告里的诡异小孩,对食物有着离谱的执念。还要注意的是,这甚至都不是照片,是画的——他们还是选择把他画成红发。我永远搞不懂 1950 年代对青春期前红发男孩的那种迷恋。</p><h2 id="能让你做噩梦的杀人狂儿童" tabindex="-1"><strong>能让你做噩梦的杀人狂儿童</strong> <a class="header-anchor" href="#能让你做噩梦的杀人狂儿童" aria-label="Permalink to &quot;**能让你做噩梦的杀人狂儿童**&quot;">​</a></h2><p><a href="https://2.bp.blogspot.com/-zAVSXTyNE5s/Ug15UwHVCRI/AAAAAAAAE48/thwQAitSpqw/s1600/26.jpg" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><p>这是梨牌香皂 (Pears&#39; Soap) 出品的某种&quot;审判&quot;。他们有广告团队,有预算。他们有的是时间。而最终,他们决定用一个正在溺水、拼命想从死神嘴里挣脱出来的婴儿。</p><p><a href="https://2.bp.blogspot.com/-fsNnlamCAvg/Ug15VCOQgCI/AAAAAAAAE5A/1az3hIcsG-o/s1600/27.jpeg" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>嗯就是一个浑身沾满血色染料的杀人小女孩。她那反社会人格的脸上没有一丝悔意。</p><p><a href="https://4.bp.blogspot.com/-ijkxlbEJlA4/Ug15V__bqtI/AAAAAAAAE5U/yoYByGIwFX8/s1600/28.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p>好,接下来这个孩子会让我未来几个星期都睡不着觉。这不是人类小孩。我脑子里只能想象自己是他爸妈,晚上走进他房间看看他,当我俯身站在他上方时,他突然睁大双眼露出那个笑容,脑袋开始 360 度旋转,然后我他妈拼命逃命。</p><p><a href="https://2.bp.blogspot.com/-OMpbLNoqGes/Ug15YYaM2qI/AAAAAAAAE6k/w2iaEp4ru7s/s1600/29.jpg" target="_blank" rel="noreferrer"><img src="'+C+'" alt=""></a></p><p>他又来了。当他不忙着用刀捅死爸妈的时候,就在忙他的广告模特事业。</p><p><a href="https://1.bp.blogspot.com/-04mk8OpAKk4/Ug15WFho7qI/AAAAAAAAE5Y/PdSCB1RRxQ0/s1600/30.jpg" target="_blank" rel="noreferrer"><img src="'+V+'" alt=""></a></p><p>他在这里根本没打算装出不邪恶的样子。不知怎么的,Karo 烹饪食品的广告团队看了这张广告,觉得它已经可以送去印刷了。</p><h2 id="极端种族主义的儿童" tabindex="-1"><strong>极端种族主义的儿童</strong> <a class="header-anchor" href="#极端种族主义的儿童" aria-label="Permalink to &quot;**极端种族主义的儿童**&quot;">​</a></h2><p><a href="https://3.bp.blogspot.com/-c7rpvs1pmzs/Ug15W2_FMWI/AAAAAAAAE5s/jVr5Lbnp2gw/s1600/31.jpg" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p><p>「你妈妈为什么不用仙女牌肥皂 (fairy soap) 给你洗澡?」多爱炫耀的小婊子。同样值得注意的是黑人女孩脸上那一等一的<strong>怒火</strong>。</p><p><a href="https://3.bp.blogspot.com/-ljqkuRXuH28/Ug15Wj-mCLI/AAAAAAAAE5o/1qBXAjpC8f4/s1600/32.jpg" target="_blank" rel="noreferrer"><img src="'+Q+'" alt=""></a></p><p>这女孩是真的豁出去了。全力开火的种族偏见。另外两个问题——那男孩为什么穿裙子?那女孩为什么在海里穿鞋?</p><p><a href="https://4.bp.blogspot.com/-PTyklGZPbjU/Ug15Xb2eWXI/AAAAAAAAE54/aiRHPhRRTkk/s1600/33.jpg" target="_blank" rel="noreferrer"><img src="'+R+'" alt=""></a></p><p>又一件梨牌肥皂 (Pears&#39; Soap) 的杰作。他们的主张是:黑人其实只是<strong>非常脏的白人</strong>。看?这位善良的白人小女孩给他洗了人生第一次澡,然后——瞧!他变白了!这哥们看起来跟我一样震惊。</p><p><a href="https://3.bp.blogspot.com/-Hxvgfq1tRSM/Ug15XwtRbVI/AAAAAAAAE6E/krSUdmyxcJQ/s1600/34.jpg" target="_blank" rel="noreferrer"><img src="'+Y+'" alt=""></a></p><p>当然了,如果洗不干净,还可以刷漆嘛!</p><p>55 到 110 岁的各位,你们生活过的年代真是不得了。</p><h2 id="胖乎乎、脸蛋红扑扑、长得一脸猥琐样、正在得意洋洋地邋遢吃东西的四岁男孩" tabindex="-1"><strong>胖乎乎、脸蛋红扑扑、长得一脸猥琐样、正在得意洋洋地邋遢吃东西的四岁男孩</strong> <a class="header-anchor" href="#胖乎乎、脸蛋红扑扑、长得一脸猥琐样、正在得意洋洋地邋遢吃东西的四岁男孩" aria-label="Permalink to &quot;**胖乎乎、脸蛋红扑扑、长得一脸猥琐样、正在得意洋洋地邋遢吃东西的四岁男孩**&quot;">​</a></h2><p>对于 40 年代这一<strong>广告主流类型</strong>,我真的不知道还能说什么了。咱们文末见吧。</p><p><a href="https://4.bp.blogspot.com/-QWdHsnAIkU4/Ug15X-ZesII/AAAAAAAAE58/uPrBY2nDVq8/s1600/35.jpg" target="_blank" rel="noreferrer"><img src="'+S+'" alt=""></a></p><p><a href="https://4.bp.blogspot.com/-qXY-FhPJSdk/Ug15YpJAfaI/AAAAAAAAE6c/cqOR0dtt2MQ/s1600/37.jpg" target="_blank" rel="noreferrer"><img src="'+W+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-C8m0hj2NWJs/Ug2cL9EOIRI/AAAAAAAAE7w/J5TlH1Np3Co/s1600/38.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt=""></a></p><p><a href="https://1.bp.blogspot.com/-9ntP5jrDWGc/Ug15ZB7CJyI/AAAAAAAAE6s/Bj_WZo3uUGY/s1600/39.jpg" target="_blank" rel="noreferrer"><img src="'+J+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-tZ_-aNY5Bp8/Ug15YGnJCiI/AAAAAAAAE6I/XXmMCc99YoA/s1600/36.jpg" target="_blank" rel="noreferrer"><img src="'+X+'" alt=""></a></p><p>我想我已经说明白了。</p><h2 id="_55-到-110-岁的各位——你们能给个说法吗" tabindex="-1">55 到 110 岁的各位——你们能给个说法吗? <a class="header-anchor" href="#_55-到-110-岁的各位——你们能给个说法吗" aria-label="Permalink to &quot;55 到 110 岁的各位——你们能给个说法吗?&quot;">​</a></h2><p>如果你喜欢 Wait But Why,欢迎订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一发布我们就发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇,还可以看看:</strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html" target="_blank" rel="noreferrer">10 种 30 岁的单身男人</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/07/medieval-people-in-bad-situations.html" target="_blank" rel="noreferrer">身处糟糕境地的中世纪人们</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/07/gods-wounded-ego.html" target="_blank" rel="noreferrer">上帝受伤的自尊心</a></strong></p><p><strong><a href="https://waitbutwhy.com/long-email-delay" target="_blank" rel="noreferrer">我是如何处理长时间未回复的邮件的</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/08/creepy-kids-in-creepy-vintage-ads.html&amp;description=Creepy%20Kids%20in%20Creepy%20Vintage%20Ads" target="_blank" rel="noreferrer"><img src="'+H+'" alt=""></a></p>',102)])])}const D=r(K,[["render",O]]);export{L as __pageData,D as default};
